1	import { detectAudioFormat } from "./magic-bytes";
2	import type { AudioSourceHandle, DecodeResult } from "./types";
3	
4	export const MAX_FILE_SIZE_BYTES = 500 * 1024 * 1024; // 500MB
5	
6	const HEADER_BYTES = 12;
7	
8	/**
9	 * Decode an audio file with validation gates:
10	 * 1. File size check (500MB limit)
11	 * 2. Magic-bytes format detection
12	 * 3. decodeAudioData
13	 */
14	export async function decodeAudioFile(
15	  file: File,
16	  ctx: BaseAudioContext,
17	): Promise<DecodeResult> {
18	  // Gate 1: file size
19	  if (file.size > MAX_FILE_SIZE_BYTES) {
20	    return {
21	      ok: false,
22	      error: {
23	        kind: "file-too-large",
24	        fileName: file.name,
25	        sizeBytes: file.size,
26	        limitBytes: MAX_FILE_SIZE_BYTES,
27	      },
28	    };
29	  }
30	
31	  // Gate 2: magic-bytes validation
32	  const headerSlice = file.slice(0, HEADER_BYTES);
33	  const headerBuf = await headerSlice.arrayBuffer();
34	  const header = new Uint8Array(headerBuf);
35	  const format = detectAudioFormat(header);
36	
37	  if (format === null) {
38	    return {
39	      ok: false,
40	      error: {
41	        kind: "unsupported-format",
42	        fileName: file.name,
43	        detectedBytes: [...header.slice(0, 4)]
44	          .map((b) => b.toString(16).padStart(2, "0"))
45	          .join(" "),
46	      },
47	    };
48	  }
49	
50	  // Gate 3: decode
51	  const arrayBuffer = await file.arrayBuffer();
52	  let audioBuffer: AudioBuffer;
53	  try {
54	    audioBuffer = await ctx.decodeAudioData(arrayBuffer);
55	  } catch {
56	    return {
57	      ok: false,
58	      error: {
59	        kind: "decode-failed",
60	        fileName: file.name,
61	        format,
62	      },
63	    };
64	  }
65	
66	  const handle: AudioSourceHandle = {
67	    id: crypto.randomUUID(),
68	    name: file.name,
69	    format,
70	    sampleRate: audioBuffer.sampleRate,
71	    channels: audioBuffer.numberOfChannels,
72	    durationSeconds: audioBuffer.duration,
73	    fileSizeBytes: file.size,
74	    createdAt: Date.now(),
75	  };
76	
77	  return { ok: true, handle, buffer: audioBuffer };
78	}
79

