1	import { describe, it, expect, vi, beforeEach, afterEach } from "vitest";
2	import { decodeAudioFile, MAX_FILE_SIZE_BYTES } from "./decode-pipeline";
3	
4	function mockAudioBuffer(opts: {
5	  length?: number;
6	  sampleRate?: number;
7	  numberOfChannels?: number;
8	  duration?: number;
9	}): AudioBuffer {
10	  const length = opts.length ?? 44100;
11	  const sampleRate = opts.sampleRate ?? 44100;
12	  const numberOfChannels = opts.numberOfChannels ?? 2;
13	  const duration = opts.duration ?? length / sampleRate;
14	  return {
15	    length,
16	    sampleRate,
17	    numberOfChannels,
18	    duration,
19	    getChannelData: () => new Float32Array(length),
20	    copyFromChannel: () => undefined,
21	    copyToChannel: () => undefined,
22	  } as unknown as AudioBuffer;
23	}
24	
25	class MockAudioContext {
26	  decodeAudioData = vi.fn<[ArrayBuffer], Promise<AudioBuffer>>();
27	}
28	
29	function wavHeader(): Uint8Array {
30	  const header = new Uint8Array(12);
31	  // RIFF
32	  header[0] = 0x52;
33	  header[1] = 0x49;
34	  header[2] = 0x46;
35	  header[3] = 0x46;
36	  // WAVE
37	  header[8] = 0x57;
38	  header[9] = 0x41;
39	  header[10] = 0x56;
40	  header[11] = 0x45;
41	  return header;
42	}
43	
44	function makeFile(
45	  name: string,
46	  headerBytes: Uint8Array,
47	  totalSize?: number,
48	): File {
49	  const size = totalSize ?? headerBytes.length;
50	  const padding =
51	    size > headerBytes.length
52	      ? new Uint8Array(size - headerBytes.length)
53	      : new Uint8Array(0);
54	  return new File([headerBytes, padding], name);
55	}
56	
57	let ctx: MockAudioContext;
58	
59	beforeEach(() => {
60	  ctx = new MockAudioContext();
61	  vi.stubGlobal("crypto", {
62	    randomUUID: () => "test-uuid-1234",
63	  });
64	});
65	
66	afterEach(() => {
67	  vi.restoreAllMocks();
68	});
69	
70	describe("decodeAudioFile", () => {
71	  it("rejects files exceeding 500MB", async () => {
72	    const bigFile = new File(["x"], "huge.wav");
73	    Object.defineProperty(bigFile, "size", { value: MAX_FILE_SIZE_BYTES + 1 });
74	
75	    const result = await decodeAudioFile(
76	      bigFile,
77	      ctx as unknown as BaseAudioContext,
78	    );
79	
80	    expect(result.ok).toBe(false);
81	    if (!result.ok) {
82	      expect(result.error.kind).toBe("file-too-large");
83	    }
84	  });
85	
86	  it("rejects files with unsupported magic bytes", async () => {
87	    const file = makeFile("mystery.bin", new Uint8Array(12));
88	
89	    const result = await decodeAudioFile(
90	      file,
91	      ctx as unknown as BaseAudioContext,
92	    );
93	
94	    expect(result.ok).toBe(false);
95	    if (!result.ok) {
96	      expect(result.error.kind).toBe("unsupported-format");
97	      expect(result.error.fileName).toBe("mystery.bin");
98	    }
99	  });
100	
101	  it("returns DecodeError when decodeAudioData fails", async () => {
102	    const file = makeFile("broken.wav", wavHeader(), 1000);
103	    ctx.decodeAudioData.mockRejectedValue(new DOMException("decode error"));
104	
105	    const result = await decodeAudioFile(
106	      file,
107	      ctx as unknown as BaseAudioContext,
108	    );
109	
110	    expect(result.ok).toBe(false);
111	    if (!result.ok) {
112	      expect(result.error.kind).toBe("decode-failed");
113	      expect(result.error.fileName).toBe("broken.wav");
114	    }
115	  });
116	
117	  it("successfully decodes a valid WAV file", async () => {
118	    const file = makeFile("kick.wav", wavHeader(), 1000);
119	    const buffer = mockAudioBuffer({
120	      sampleRate: 44100,
121	      numberOfChannels: 2,
122	      duration: 1.5,
123	    });
124	    ctx.decodeAudioData.mockResolvedValue(buffer);
125	
126	    const result = await decodeAudioFile(
127	      file,
128	      ctx as unknown as BaseAudioContext,
