1	import {
2	  render,
3	  screen,
4	  fireEvent,
5	  act,
6	  cleanup,
7	} from "@testing-library/react";
8	import { describe, it, expect, vi, beforeEach, afterEach } from "vitest";
9	import { App } from "./App";
10	import { useDawStore } from "@state/store";
11	import { createInMemoryStorage } from "@audio/media-pool/idb-storage";
12	
13	vi.mock("@audio/media-pool/idb-storage", async (importOriginal) => {
14	  const actual =
15	    await importOriginal<typeof import("@audio/media-pool/idb-storage")>();
16	  return {
17	    ...actual,
18	    createIndexedDBStorage: (): ReturnType<typeof createInMemoryStorage> =>
19	      actual.createInMemoryStorage(),
20	  };
21	});
22	
23	vi.mock("@state/session/index", async (importOriginal) => {
24	  const actual = await importOriginal<typeof import("@state/session/index")>();
25	  return {
26	    ...actual,
27	    createIndexedDBSessionStorage: actual.createInMemorySessionStorage,
28	  };
29	});
30	
31	function createMockGainNode(): GainNode {
32	  return {
33	    gain: { value: 1, setValueAtTime: vi.fn(), setTargetAtTime: vi.fn() },
34	    connect: vi.fn().mockReturnThis(),
35	    disconnect: vi.fn(),
36	  } as unknown as GainNode;
37	}
38	
39	function createMockOscillatorNode(): OscillatorNode {
40	  return {
41	    type: "sine",
42	    frequency: { value: 0, setValueAtTime: vi.fn() },
43	    connect: vi.fn().mockReturnThis(),
44	    start: vi.fn(),
45	    stop: vi.fn(),
46	    disconnect: vi.fn(),
47	  } as unknown as OscillatorNode;
48	}
49	
50	class MockAudioContext {
51	  state: AudioContextState = "suspended";
52	  readonly sampleRate = 44100;
53	  currentTime = 0;
54	  readonly destination = {} as AudioDestinationNode;
55	  readonly audioWorklet = {
56	    addModule: vi.fn().mockResolvedValue(undefined),
57	  };
58	  createGain(): GainNode {
59	    return createMockGainNode();
60	  }
61	  createOscillator(): OscillatorNode {
62	    return createMockOscillatorNode();
63	  }
64	  createDynamicsCompressor(): DynamicsCompressorNode {
65	    return {
66	      threshold: { value: -24, setValueAtTime: vi.fn() },
67	      ratio: { value: 12, setValueAtTime: vi.fn() },
68	      knee: { value: 30, setValueAtTime: vi.fn() },
69	      attack: { value: 0.003, setValueAtTime: vi.fn() },
70	      release: { value: 0.25, setValueAtTime: vi.fn() },
71	      connect: vi.fn().mockReturnThis(),
72	      disconnect: vi.fn(),
73	    } as unknown as DynamicsCompressorNode;
74	  }
75	  createAnalyser(): AnalyserNode {
76	    return {
77	      connect: vi.fn().mockReturnThis(),
78	      disconnect: vi.fn(),
79	      fftSize: 2048,
80	    } as unknown as AnalyserNode;
81	  }
82	  createStereoPanner(): StereoPannerNode {
83	    return {
84	      pan: { value: 0, setValueAtTime: vi.fn() },
85	      connect: vi.fn().mockReturnThis(),
86	      disconnect: vi.fn(),
87	    } as unknown as StereoPannerNode;
88	  }
89	  resume(): Promise<void> {
90	    this.state = "running";
91	    return Promise.resolve();
92	  }
93	  close(): Promise<void> {
94	    this.state = "closed";
95	    return Promise.resolve();
96	  }
97	}
98	
99	beforeEach(() => {
100	  vi.stubGlobal("AudioContext", MockAudioContext);
101	  useDawStore.setState({ engineStatus: "uninitialized" });
102	});
103	
104	afterEach(() => {
105	  cleanup();
106	  vi.restoreAllMocks();
107	});
108	
109	describe("App", () => {
110	  it("shows error when not cross-origin isolated", () => {
111	    vi.stubGlobal("crossOriginIsolated", false);
112	    render(<App />);
113	    expect(screen.getByRole("alert")).toBeInTheDocument();
114	    expect(
115	      screen.getByText("Cross-Origin Isolation Required"),
116	    ).toBeInTheDocument();
117	  });
118	
119	  it("shows click-to-start when cross-origin isolated", () => {
120	    vi.stubGlobal("crossOriginIsolated", true);
121	    render(<App />);
122	    expect(screen.getByText("BRUTALWAV")).toBeInTheDocument();
123	    expect(screen.getByText("Click to start audio engine")).toBeInTheDocument();
124	  });
125	
126	  it("shows DAW shell after clicking start", async () => {
127	    vi.stubGlobal("crossOriginIsolated", true);
128	    render(<App />);
129	    await act(async () => {
130	      fireEvent.click(screen.getByRole("button"));
131	      await Promise.resolve();
132	    });
133	    expect(screen.getByTestId("daw-shell")).toBeInTheDocument();
134	    expect(useDawStore.getState().engineStatus).toBe("running");
135	  });
136	
137	  it("sets engine status to error when resume() rejects", async () => {
138	    vi.stubGlobal("crossOriginIsolated", true);
139	    vi.stubGlobal(
140	      "AudioContext",
141	      class extends MockAudioContext {
142	        override resume(): Promise<void> {
143	          return Promise.reject(new Error("autoplay blocked"));
144	        }
145	      },
146	    );
147	    render(<App />);
148	    await act(async () => {
149	      fireEvent.click(screen.getByRole("button"));
150	      await Promise.resolve();
151	    });
152	    expect(useDawStore.getState().engineStatus).toBe("error");
153	    expect(screen.getByText("BRUTALWAV")).toBeInTheDocument();
154	  });
155	
156	  it("sets engine status to error when AudioContext constructor throws", () => {
157	    vi.stubGlobal("crossOriginIsolated", true);
158	    vi.stubGlobal(
159	      "AudioContext",
160	      vi.fn(() => {
161	        throw new Error("Web Audio not supported");
162	      }),
163	    );
164	    render(<App />);
165	    act(() => {
166	      fireEvent.click(screen.getByRole("button"));
167	    });
168	    expect(useDawStore.getState().engineStatus).toBe("error");
169	    expect(screen.getByText("BRUTALWAV")).toBeInTheDocument();
170	  });
171	
172	  it("does not create a second AudioContext on double-click", async () => {
173	    vi.stubGlobal("crossOriginIsolated", true);
174	    const constructorSpy = vi.fn();
175	    vi.stubGlobal(
176	      "AudioContext",
177	      class extends MockAudioContext {
178	        constructor() {
179	          super();
180	          constructorSpy();
181	        }
182	      },
183	    );
184	    render(<App />);
185	    const button = screen.getByRole("button");
186	    await act(async () => {
187	      fireEvent.click(button);
188	      fireEvent.click(button);
189	      await Promise.resolve();
190	    });
191	    expect(constructorSpy).toHaveBeenCalledTimes(1);
192	  });
193	
194	  it("closes AudioContext when resume() rejects", async () => {
195	    vi.stubGlobal("crossOriginIsolated", true);
196	    const closeSpy = vi.fn().mockResolvedValue(undefined);
197	    vi.stubGlobal(
198	      "AudioContext",
199	      class extends MockAudioContext {
200	        override resume(): Promise<void> {
201	          return Promise.reject(new Error("autoplay blocked"));
202	        }
203	        override close(): Promise<void> {
204	          closeSpy();
205	          return Promise.resolve();
206	        }
207	      },
208	    );
209	    render(<App />);
210	    await act(async () => {
211	      fireEvent.click(screen.getByRole("button"));
212	      await Promise.resolve();
213	    });
214	    expect(closeSpy).toHaveBeenCalledTimes(1);
215	  });
216	
217	  it("does not update state if unmounted while resume() is in flight", async () => {
218	    vi.stubGlobal("crossOriginIsolated", true);
219	    let resolveResume: (() => void) | undefined;
220	    const resumePromise = new Promise<void>((r) => {
221	      resolveResume = r;
222	    });
223	    const closeSpy = vi.fn().mockResolvedValue(undefined);
