    expect(screen.getByRole("button")).not.toBeDisabled();
    await act(async () => {
      fireEvent.click(screen.getByRole("button"));
      await flushMicrotasks();
    });
    expect(onStart).toHaveBeenCalledTimes(2);
  });
});

